insert into public.concepts
  (id, term, aliases, said, alias_list, status, one_liner, analogy, example, related, deeper, lens_pm, lens_eng, domain, priority, tags)
values
  ('ondeviceinference', 'On-Device Inference', '', '', ARRAY['edge inference']::text[], 'Core', 'Running the model directly on your phone, laptop, or edge device instead of sending requests to a server.', 'Like keeping a calculator in your pocket instead of calling a math hotline every time you need an answer.', 'Running Llama 2 on an iPhone to power offline voice commands without internet.', '[{"text":"Reduces latency and privacy risk vs.","id":"inference"},{"text":"Often paired with.","id":"quantization"}]'::jsonb, 'Trades server latency and privacy concerns for local latency and device compute constraints. The model fits in available VRAM, usually through quantization and optimization. Requires careful memory management and cannot leverage cloud scaling.', 'Enables privacy-preserving features and offline functionality, but constrains model capability to what fits locally.', 'Model inference executes on the users device CPU/GPU using optimized frameworks like Core ML, ONNX, or llama.cpp.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('localinference', 'Local Inference', '', '', ARRAY['self-hosted']::text[], 'Core', 'Running model inference on your own machine or private infrastructure, not on a cloud providers servers.', 'Storing documents in your filing cabinet instead of using a cloud service.', 'Using ollama to run an open-source LLM on your laptop for RAG without paying per API call.', '[{"text":"Complementary to.","id":"inference"}]'::jsonb, 'Includes both on-device inference and self-hosted servers. Requires ownership of compute hardware, model weights, and infrastructure. Offers full control and data privacy but demands operational expertise and hardware investment.', 'Locks in infrastructure cost but eliminates per-token variable costs and prevents vendor lock-in.', 'Inference loops run on self-managed compute—bare metal, containerized, or minimal orchestration—not via third-party APIs.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('serverlessinferen', 'Serverless Inference', '', '', ARRAY['serverless','function-as-service']::text[], 'Rising', 'Running inference without managing servers—you pay per request and the infrastructure scales automatically.', 'Calling a taxi instead of owning a car; you only pay when you use it.', 'AWS Lambda powered by provisioned throughput to serve a model on-demand without maintaining EC2 instances.', '[{"text":"Trades off vs.","id":"inference"},{"text":"Complements.","id":"containerization"}]'::jsonb, 'Request handler spins up, inference completes, handler shuts down. Cold starts introduce latency. Pricing is request-based, not reservation-based. Best for bursty, low-volume workloads or strict SLAs that do not require always-on availability.', 'Eliminates infrastructure management overhead and scales to zero cost when idle, but adds latency for cold starts.', 'Model loaded into ephemeral function runtime; inference executes within request window, then container is deallocated.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('containerization', 'Containerization', '', '', ARRAY['container','Docker','OCI']::text[], 'Core', 'Packaging model, dependencies, and runtime into a lightweight, portable unit that runs anywhere.', 'Shipping goods in a standardized cargo container that fits any port and truck.', 'A Dockerfile that installs dependencies, loads model weights, and runs an inference server—deploy to cloud or on-prem unchanged.', '[{"text":"Enabler for.","id":"kubernetes"}]'::jsonb, 'Container includes OS libraries, Python environment, model, and app. Isolates dependencies and avoids "works on my machine" problems. OCI standard ensures compatibility. Overhead is minimal compared to VMs but requires orchestration at scale.', 'Simplifies deployment across environments and enables faster, more reliable scaling.', 'Image built from Dockerfile, pushed to registry, pulled and run by orchestrator; filesystem and process isolation guarantee consistent runtime.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('kubernetes', 'Kubernetes', '', '', ARRAY['K8s','k8s']::text[], 'Core', 'Open-source system for automating deployment, scaling, and management of containerized applications.', 'A conductor managing an orchestra—assigns instruments to musicians, replaces broken ones, scales up for large halls.', 'Declare desired replicas of an inference container; K8s ensures the count is maintained and routes traffic across healthy pods.', '[{"text":"Orchestrates.","id":"containerization"},{"text":"Sits below.","id":"mlops"}]'::jsonb, 'Abstracts underlying hardware. Handles pod placement, resource allocation, rolling updates, self-healing, and networking. Learning curve is steep; day-2 operations (monitoring, upgrades, storage) demand expertise. Not needed for small, static deployments.', 'Enables reliable, multi-cloud deployment and auto-scaling but adds operational complexity.', 'Declarative system; etcd stores cluster state; controllers watch and reconcile; kubelet on nodes enforces spec.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('modelregistry', 'Model Registry', '', '', ARRAY['model store','model catalog']::text[], 'Rising', 'Central repository that tracks model versions, metadata, and lineage—who trained it, what data, which metrics.', 'A library card catalog that lists every books author, edition, and condition.', 'MLflow Model Registry storing model artifacts, stage (dev/prod), and approval history so teams share the source of truth.', '[{"text":"Stores.","id":"checkpoint"},{"text":"Enables.","id":"versioning"}]'::jsonb, 'Solves model sprawl—teams lose track of which version is in production and why. Enables rollbacks, A/B testing, and compliance audits. Integration with CI/CD and serving systems ensures consistency. Can be as simple as S3 with metadata or as elaborate as MLflow/DVC.', 'Reduces deployment incidents and accelerates time to production by removing ambiguity.', 'API to register, retrieve, and tag model artifacts; integrates with serving systems to pull correct version at runtime.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('versioning', 'Versioning', '', '', ARRAY['model version','version control','semantic versioning']::text[], 'Core', 'Tracking model changes over time so you can reproduce results, rollback, and understand what changed between versions.', 'Git for your model; each commit is a snapshot with metadata and a message.', 'Model v1.0 trained on 2024 data scores 92% accuracy; v1.1 with 2025 data scores 91%—rollback to v1.0 if needed.', '[{"text":"Tracked by.","id":"modelregistry"}]'::jsonb, 'Enables reproducibility: same version + same code + same data = same results. Must version not just weights but also preprocessing, tokenization, and dependencies. Semantic versioning (major.minor.patch) signals compatibility and significance of changes.', 'Speeds incident response (instant rollback) and compliance reporting (audit trail).', 'Artifacts tagged with version string, checksummed, and linked to code commit and dataset version; serving layer selects version at runtime.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('canarydeploym', 'Canary Deployment', '', '', ARRAY['canary release']::text[], 'Core', 'Rolling out a new model to a small fraction of traffic first, then gradually increasing if metrics look good.', 'Coal miners brought canaries into mines to detect poisonous gas early; new model is your canary.', 'Route 5% of requests to the new model v1.1, monitor latency and accuracy, then increment to 50% if all looks well.', '[{"text":"Variant of."}]'::jsonb, 'Mitigates blast radius of buggy or degraded models. Requires ability to split traffic, capture metrics, and rollback automatically. Drift detection rules trigger automated rollback. Can run multiple versions in parallel to compare. Good for high-stakes production systems.', 'Dramatically reduces risk of model updates while maintaining continuous improvement velocity.', 'Traffic router (Envoy, istio, or application code) weights requests; observability pipeline monitors canary metrics vs baseline; automated rollback if error rate or latency exceeds threshold.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('bluegreendep', 'Blue-Green Deployment', '', '', ARRAY['blue-green','twin deployment']::text[], 'Core', 'Keep two identical production environments—blue (current) and green (next)—flip traffic only after green is healthy.', 'Having a stunt double ready; if the double is fine, the star walks off stage and the double takes over.', 'Both blue and green clusters run in parallel; traffic flows to blue; green is tested and validated; flip the load balancer to green; decommission blue.', '[{"text":"Variant of."},{"text":"Pairs well with."}]'::jsonb, 'Zero-downtime deployment with instant rollback. Requires double the infrastructure cost temporarily. Good for large, monolithic systems. Can pair with canary for even lower risk. Requires health checks and smoke tests to validate green before flip.', 'Enables high-confidence, zero-downtime deployments at cost of doubled temporary infrastructure.', 'DNS or load balancer points to blue or green; deployment automation validates green, then flips the selector; blue remains on standby for instant rollback.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('rollback', 'Rollback', '', '', ARRAY['revert','rollback']::text[], 'Core', 'Instantly revert to a previous version if something goes wrong—switch traffic back to the old model or code.', 'Hitting undo after a bad edit.', 'New model v1.2 causes 5x error rate spike; revert to v1.1 while team debugs the issue.', '[{"text":"Enabled by.","id":"versioning"},{"text":"Triggered by."}]'::jsonb, 'Speed of rollback directly affects blast radius. Requires pre-tested fallback version running in parallel (blue-green or canary). Automated triggers (error rate threshold, latency spike) initiate rollback without human intervention. Test rollbacks regularly to ensure they work under stress.', 'Insurance policy that lets teams ship fast and recover quickly if things break.', 'Traffic selector or DNS points back to stable version; circuit breaker or health check validates old version is healthy; telemetry confirms rollback succeeded.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('alerting', 'Alerting', '', '', ARRAY['alert','alert rule','alarm']::text[], 'Core', 'Automated notifications when metrics or logs hit a threshold—latency spike, error rate jump, model drift.', 'A smoke alarm that wakes you up when there is danger, not you checking the house every minute.', 'Inference latency p99 > 500ms triggers a PagerDuty alert; on-call engineer sees it within 30 seconds.', '[{"text":"Driven by."}]'::jsonb, 'Alert fatigue kills response: if 90% of alerts are false positives, the on-call engineer will ignore them. Tune thresholds carefully and use multi-signal rules (not just one metric). Routing rules send the right alert to the right team. Must include runbook links to unblock engineers.', 'Dramatically shortens time-to-incident and time-to-resolution.', 'Rules engine (Prometheus, Datadog, CloudWatch) evaluates conditions on metrics; fires webhook, email, or SMS; integrates with incident management.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('tracing', 'Tracing', '', '', ARRAY['distributed tracing']::text[], 'Rising', 'Following a single request through all services—inference server calls embedding service which queries vector DB—to find bottlenecks.', 'Painting a drop of food coloring into a river and tracking where it goes.', 'A request spans: model loading (50ms) then prompt build (10ms) then inference (200ms) then token streaming (150ms) = 410ms end-to-end.', '[{"text":"Complements."},{"text":"Paired with."}]'::jsonb, 'Logs let you ask "what happened?" Traces let you ask "how did this request get here and why was it slow?" Requires instrumentation in code (OpenTelemetry) and a collector (Jaeger, Datadog). Sampling is critical—tracing every request is expensive; sample high-latency requests more often.', 'Pinpoints exact bottlenecks in production without guessing.', 'Instrumentation in code creates spans; each span tags service, duration, metadata; collector gathers spans into traces; UI shows waterfall chart.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('metrics', 'Metrics', '', '', ARRAY['metric','time-series','KPI']::text[], 'Core', 'Numerical measurements over time—latency, throughput, error rate, cost—aggregated for trend analysis.', 'Your heart rate monitor showing beats-per-minute over the day so you can spot workout vs rest patterns.', 'Inference latency p50=100ms, p95=250ms, p99=500ms; throughput 1000 requests/sec; cost $0.001 per inference.', '[{"text":"Displayed in.","id":"dashboards"},{"text":"Triggering.","id":"alerting"}]'::jsonb, 'Time-series databases (Prometheus, InfluxDB) store high-cardinality metrics. Cardinality explosion (unique label combinations) makes storage expensive and queries slow. Rules aggregate (sum, rate, histogram) to make alerting feasible. Dimensionality (service, model, region) enables slicing but explodes cardinality.', 'Quantifies system health and ROI—track latency, cost, and quality metrics to guide decisions.', 'Instrumentation emits counters (requests), gauges (queue length), histograms (latency); time-series DB stores; query engine aggregates for dashboards and alerts.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('dashboards', 'Dashboards', '', '', ARRAY['dashboard','grafana','data viz']::text[], 'Core', 'Real-time visual display of metrics and logs—graphs, heat maps, tables—so you spot issues at a glance.', 'Car dashboard showing speed, fuel, engine temp; you do not need to ask the car for data, you just look.', 'Production dashboard showing model latency, error rate, and cost-per-request updated every 5 seconds.', '[{"text":"Display.","id":"metrics"},{"text":"Triggered by."}]'::jsonb, 'Useful dashboards tell a story—one per persona (product manager wants cost trends, engineer wants latency distribution). Avoid chart-salad: a wall of 50 charts hides what matters. Drill-down capability lets you zoom from "system is slow" to "model A in region B is the culprit." Link to runbooks for common issues.', 'Instant visibility into system health and cost to drive operational decisions.', 'Grafana, Datadog, or custom visualization queries metrics DB and renders time-series graphs; includes alerts and drill-down links.', 'Infrastructure & serving', 80, ARRAY['seed','infrastructure-serving']::text[]),
  ('throughputopt', 'Throughput Optimization', '', '', ARRAY['batch optimization','qps']::text[], 'Rising', 'Maximizing the number of requests a server can handle per second by optimizing batching, memory, and compute.', 'Fitting more passengers on a bus by optimal seating vs wasted aisle space.', 'Batch size 128 achieves 1000 req/sec; batch size 64 achieves 600 req/sec; batch size 256 hits OOM—optimal is 128.', '[{"text":"Related to.","id":"latency"},{"text":"Measured by.","id":"throughput"}]'::jsonb, 'Throughput limited by either compute (FLOPS fully utilized, waiting for more data) or memory (cannot fit larger batch). Continuous batching and KV cache optimization critical for LLMs. Hardware choice matters: tensor cores, memory bandwidth. Software profiling identifies bottleneck. Diminishing returns: doubling batch size does not double throughput.', 'Higher throughput = lower cost-per-request = better economics.', 'Profile inference time across batch sizes; optimize memory layout and compute kernels; measure utilization and identify bottleneck (compute vs memory bound).', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('pagedattention', 'Paged Attention', '', '', ARRAY['paged attention','attention paging']::text[], 'Rising', 'Virtual memory for KV cache: pages of cache are allocated and freed dynamically, avoiding fragmentation and wasted VRAM.', 'Instead of allocating one huge contiguous block for each request, use small pages that the OS can juggle.', 'Request needs 256MB KV cache; allocate 256 4MB pages, not a single 256MB block; other requests can use freed pages without fragmentation.', '[{"text":"Optimizes.","id":"kvcache"},{"text":"Reduces.","id":"vram"}]'::jsonb, 'Classic KV cache allocation wastes 90% of memory due to fragmentation (sequences end at different lengths). Paged attention treats cache as virtual memory: pages can be non-contiguous, oversubscribed, evicted. vLLM pioneered this for LLM inference. Reduces effective VRAM requirements by 10x for some workloads.', 'Dramatically improves serving throughput and cost efficiency by reducing memory waste.', 'Kernel allocates cache pages on demand; scheduler pages KV for sequences; can oversubscribe VRAM using host memory.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('tensorcores', 'Tensor Cores', '', '', ARRAY['tensor core','NVIDIA tensor core','specialized compute']::text[], 'Rising', 'Specialized hardware units in GPUs that perform matrix multiplications ultra-fast, the core operation of neural networks.', 'A carpenter with a power drill instead of a hand drill—same job, orders of magnitude faster.', 'H100 Tensor Cores deliver 1.5 PetaFLOPS for matrix ops; CPU cannot compete.', '[{"text":"Found in.","id":"gpu"}]'::jsonb, 'Tensor Cores multiply two matrices in a single cycle. Requires data to be in the right format (Tensor Float 32, BFloat16). Not all operations use Tensor Cores—memory bandwidth becomes bottleneck for attention. Modern GPUs have multiple types (TF32, BF16, FP8) for different precisions.', 'Determines inference and training speed; choose hardware with the right Tensor Cores for your model precision.', 'Use libraries (cuBLAS, CUTLASS) that map operations to Tensor Cores; avoid data format conversions that stall pipelines.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('distributedinferen', 'Distributed Inference', '', '', ARRAY['distributed inference','sharded inference','multi-gpu']::text[], 'Rising', 'Split model across multiple GPUs or machines so it fits in VRAM and requests parallelize across devices.', 'A large jigsaw puzzle split across four tables so you can assemble it faster with four people.', '70B model will not fit on one A100; shard across two A100s using tensor parallelism; request takes same latency but you serve 2x throughput.', '[{"text":"Opposite of.","id":"modelparallelism"}]'::jsonb, 'Tensor parallelism splits weight matrices (each GPU holds rows of weight); pipeline parallelism splits layers (GPU0 has layers 1-20, GPU1 has layers 21-40). Communication overhead (all-reduce, all-gather) can negate speedup if link is slow. Best on NVLink or InfiniBand; bad on 1Gbps Ethernet.', 'Enables serving of massive models that do not fit on single GPU.', 'Model partitioned during load; forward pass communicates between GPUs; orchestrator (vLLM, TensorRT-LLM) handles communication patterns.', 'Infrastructure & serving', 60, ARRAY['seed','infrastructure-serving']::text[]),
  ('visionmodel', 'Vision Model', '', '', ARRAY['vision','visual model','image model']::text[], 'Core', 'Neural network trained to process images and understand visual content—classify objects, detect faces, or describe scenes.', 'Teaching a kid to recognize animals in a picture instead of just reading a list of words.', 'ResNet-50 classifies 1000 object categories from ImageNet; YOLO detects people and cars in real-time video.', '[{"text":"Foundation for.","id":"vlm"},{"text":"Complements.","id":"languagemodel"}]'::jsonb, 'Convolutional layers slide filters across images, learning textures and shapes. Hierarchical: early layers learn edges, middle layers learn parts, late layers learn objects. Pre-trained on ImageNet then fine-tuned. More data-hungry than text models; 100k labeled images is a large dataset.', 'Opens product capabilities in computer vision: content moderation, visual search, autonomous driving features.', 'Backbone (ResNet, EfficientNet, ViT) extracts image features; head (classification, detection, segmentation) performs task-specific prediction.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('vlm', 'VLM', '', '', ARRAY['vision language model','multimodal model','vision LLM']::text[], 'Core', 'Neural network that understands both images and text—can caption photos, answer questions about images, or generate images from descriptions.', 'A person who can read, write, and understand pictures—richer than someone who only reads or only looks.', 'GPT-4V takes an image and asks "what is in this photo?" and responds "a beach sunset with people swimming"; CLIP retrieves images matching text queries.', '[{"text":"Combines.","id":"visionmodel"},{"text":"and.","id":"languagemodel"}]'::jsonb, 'Vision encoder (ResNet, ViT) extracts image embeddings; text encoder converts words to embeddings; both sit in same space for alignment. Training requires image-text pairs (billions from web-scraped captions). More powerful than separate vision and text models but more compute-intensive.', 'Enables richer user experiences: visual search, image Q&A, content understanding for moderation.', 'Two-tower architecture: image tower outputs embeddings, text tower outputs embeddings; contrastive loss aligns them; downstream tasks use aligned space.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('imageencoder', 'Image Encoder', '', '', ARRAY['image embedding','visual encoder','image feature extractor']::text[], 'Core', 'Neural network component that converts images into dense vector representations so images can be compared and retrieved.', 'Reducing a photo to its essence—color palette, composition, key objects—rather than storing every pixel.', 'ResNet outputs 2048-d embeddings; two cat photos produce very similar embeddings even if one is closer-up; dissimilar images are far apart in embedding space.', '[{"text":"Component of.","id":"vlm"},{"text":"Powers."}]'::jsonb, 'Vision models like ViT or CLIP produce embeddings. Embeddings trained to be similar for semantically related images (contrastive learning with image-image pairs or image-text pairs). Can be used for image search, deduplication, or as feature input to downstream models.', 'Powers visual search and similarity-based recommendations.', 'Forward pass of image through network backbone up to penultimate layer; output is a 512-2048-d vector; stored in vector DB for search.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('ocr', 'OCR', '', '', ARRAY['optical character recognition','text recognition','document reading']::text[], 'Core', 'Converting images of text (scans, photos) into machine-readable text strings.', 'Transcribing a handwritten letter so you can search and edit it.', 'Scan a receipt; OCR extracts "Total: $42.50, Date: 2025-01-16"; you can now search for this expense in your records.', '[{"text":"Subtask of."}]'::jsonb, 'Combines vision (detect text regions) and sequence modeling (recognize characters). Classic approaches (Tesseract) struggled with curved text and low quality; modern deep learning (CRAFT + attention-based sequence-to-sequence) is more robust. End-to-end models learn bounding box detection and character recognition jointly.', 'Unlocks automation: invoice processing, document search, accessibility (read aloud).', 'Text detection network (YOLO-style) finds text boxes; character recognition network (sequence-to-sequence) decodes characters within each box.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('objectdetect', 'Object Detection', '', '', ARRAY['detection','YOLO','bounding box']::text[], 'Core', 'Identifying and locating multiple objects in an image—boxing where each is and labeling what it is.', 'Circling every person in a crowd photo and writing their name.', 'YOLO detects "person" at (100, 50, 300, 400), "car" at (450, 200, 600, 350) in one forward pass.', '[{"text":"Related to."},{"text":"Enables."}]'::jsonb, 'Classification says "this image has dogs"; detection says "dog at top-left, dog at bottom-right." Requires bounding box regression (predict coordinates) plus classification. YOLO is fast one-stage detector; Faster R-CNN is two-stage (region proposal then classification). Training requires bounding box annotations, expensive to collect.', 'Enables autonomous driving, security monitoring, content moderation (what objects appear in a scene?).', 'Network predicts class probabilities and bounding boxes for each anchor; NMS (non-maximum suppression) removes duplicate detections.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('segmentation', 'Segmentation', '', '', ARRAY['semantic segmentation','pixel-level','segmentation mask']::text[], 'Core', 'Classifying every pixel in an image so you know exactly which region belongs to what object.', 'Coloring each pixel of a map by country instead of just drawing borders.', 'Medical imaging: segment tumor pixels (red), healthy tissue (blue), background (gray) so surgeon sees exactly what to remove.', '[{"text":"Refinement of.","id":"objectdetect"}]'::jsonb, 'Pixel-level prediction; many times slower than classification or detection. Encoder-decoder architecture: encoder downsamples (learn features), decoder upsamples (restore resolution). Skip connections preserve fine detail. Requires pixel-level annotations, extremely expensive (weeks of manual labeling per image).', 'Critical for robotics, medical imaging, autonomous driving—need precise region boundaries.', 'Encoder-decoder network outputs logits per pixel; cross-entropy loss on each pixel; typically uses U-Net or transformer architecture.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('imagecaption', 'Image Captioning', '', '', ARRAY['caption generation','image description','visual description']::text[], 'Core', 'Generating a natural language description of an image—what objects, actions, and relationships appear in the photo.', 'Writing an alt-text for an image that sighted users cannot see.', '"A person hiking in the mountains with a sunset in the background" from a photo of a hiker silhouetted against dusk.', '[{"text":"Variant of.","id":"vlm"}]'::jsonb, 'Combines vision encoder (CNN or ViT) with sequence generation (LSTM or transformer decoder). Training pairs images with human-written captions. Generated captions are often generic or miss fine details. Beam search during inference trades speed for quality.', 'Accessibility feature and enables search by description.', 'Image encoder outputs embeddings; decoder attends to embeddings and generates words token-by-token; beam search finds top-k captions.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('clip', 'CLIP', '', '', ARRAY['CLIP','contrastive vision','zero-shot vision']::text[], 'Core', 'OpenAIs model that learns to match image and text embeddings, enabling zero-shot classification and semantic image search without any training.', 'Learning that "dog photo" and "text: dog" are similar without ever being told "class 0 is dog."', 'CLIP can classify images into 1000 categories without seeing a single example—just from the class names like "Labrador" or "Poodle."', '[{"text":"Foundation for.","id":"vlm"},{"text":"Enables.","id":"zeroshot"}]'::jsonb, 'Trained on 400M image-text pairs from web using contrastive loss: pull matching pairs close, push mismatched pairs apart. Image and text encoders output embeddings in shared space. Zero-shot via: embed new classes ("a photo of a {class}"), embed image, pick nearest class. Enabled by scale and diverse internet data.', 'Massively reduces labeling burden; one model works for any classification task.', 'Dual-encoder: image encoder + text encoder output to shared embedding space; contrastive loss during training; at test time, embed image and text, compute cosine similarity.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('imagegeneration', 'Image Generation', '', '', ARRAY['generative model','image synthesis','conditional generation']::text[], 'Core', 'Creating new, realistic images from scratch or conditioned on a description, sketch, or example.', 'An artist drawing a picture from your verbal description.', '"A robot painting in Van Goghs style" generates a novel image that has never existed—no copyright, new synthesis.', '[{"text":"Based on.","id":"diffusionmodel"},{"text":"Variant.","id":"texttoimagegeneration"}]'::jsonb, 'Diffusion models (iterative denoising) are now dominant over GANs. Start with noise, iteratively denoise guided by text embedding or other conditioning. Training requires billions of image-text pairs. Inference takes 20-50 steps (seconds on GPU). Quality improves with compute; 4K outputs are now feasible.', 'Opens creative use cases: design mockups, stock imagery, avatar generation, personalization.', 'Text encoder converts prompt to embeddings; UNet denoising network reverses Gaussian noise 50 steps guided by embeddings; outputs image.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('texttoimagegeneration', 'Text-to-Image', '', '', ARRAY['text2image','prompt-to-image','generative image']::text[], 'Core', 'Creating images from natural language descriptions—"a cyberpunk city at night" produces a novel picture matching the description.', 'Commissioning a digital artist who reads your description and delivers a painting in seconds.', 'DALL-E, Midjourney, Stable Diffusion take text prompts and generate photorealistic or artistic images.', '[{"text":"Specialization of.","id":"imagegeneration"}]'::jsonb, 'Relies on text encoder (CLIP or BERT-style) to convert prompt to embeddings, then diffusion or GAN uses embeddings to guide generation. Model must learn mapping between language and pixels. Prompt engineering (specific adjectives, artist names, style hints) dramatically improve results.', 'Unlocks content creation and design workflows without hiring artists.', 'Text encoder + diffusion backbone; conditioning signal injected via cross-attention; noise schedule controls quality-speed tradeoff.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('diffusionmodelpm', 'Diffusion', '', '', ARRAY['denoising','diffusion process']::text[], 'Core', 'Iteratively adding noise to images then learning to reverse the process, generating sharp images from random noise.', 'Rewinding a video of fog rolling in until you see the landscape appear from mist.', 'Start with random noise, denoise 50 times, each step reveals more detail until a clear image emerges.', '[{"text":"Used in.","id":"imagegeneration"},{"text":"Alternative to.","id":"gan"}]'::jsonb, 'Markov chain that gradually adds noise to images until they are pure noise; training objective learns reverse process (denoise). Forward process and reverse process are both Gaussians; posterior can be computed analytically. Conditioning (text, image, class) guides denoising. Sampling uses DDPM, DDIM, or Euler steppers.', 'Most reliable generative model; consistent quality; can be run locally; becoming standard for content generation.', 'UNet backbone predicts noise at each timestep; train with MSE loss on predicted noise; sample with iterative denoising.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('stablediffusion', 'Stable Diffusion', '', '', ARRAY['SD','SD1.5','SD2.1','Stability AI']::text[], 'Core', 'Open-source text-to-image diffusion model that runs on consumer GPUs and sparked the generative AI art boom.', 'The Linux of generative AI—free, open, customizable, and community-driven.', 'Local SD 1.5 with 4GB VRAM generates a 512x512 image in 20 seconds; no API costs or privacy concerns.', '[{"text":"Example of.","id":"diffusionmodelpm"},{"text":"Enables."}]'::jsonb, 'Latent diffusion: compress images to latent space via VAE, diffuse in latent space, decode back to pixel space. Much faster than pixel diffusion. Released open-source in 2022, sparking community fine-tunes (LoRA, textual inversion, ControlNet). Model weights available; enables fine-tuning and local deployment.', 'Democratized image generation; eliminated dependency on proprietary APIs.', 'VAE encoder compresses image to latent; UNet with attention in latent space; CLIP encoder guides; VAE decoder reconstructs.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('inpainting', 'Inpainting', '', '', ARRAY['inpaint','context inpainting','image inpainting']::text[], 'Core', 'Filling in missing or masked regions of an image based on surrounding context—remove objects, fill holes, extend scenes.', 'Using Photoshop content-aware fill but 100x more realistic.', 'Mask a person out of a photo; inpainting reconstructs the background as if they were never there.', '[{"text":"Variant of.","id":"diffusionmodelpm"}]'::jsonb, 'Diffusion model conditioned on masked image and mask. Learn to hallucinate content that matches surrounding pixels. Can also condition on text ("replace the person with a robot") for guided inpainting. Training uses images with random masks and content; inference provides mask and sometimes text.', 'Enables photo editing at scale; remove logos, watermarks, or unwanted objects without hiring Photoshop experts.', 'Masked image and mask concatenated with model input; diffusion conditioned on both; noise only diffused in masked regions.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('outpainting', 'Outpainting', '', '', ARRAY['outpaint','image extension','canvas expansion']::text[], 'Core', 'Extending an image beyond its borders by imagining what should fill the new space.', 'Panning out from a photo so you see more of the scene that was off-screen.', 'A 512x512 portrait of a person; outpaint to 1024x512 to show more of the background and surroundings.', '[{"text":"Inverse of.","id":"inpainting"}]'::jsonb, 'Similar to inpainting but mask is around the edges. Model must maintain consistency with existing content while generating new pixels. Requires careful conditioning to avoid jarring discontinuities. Works better in certain directions (panning left easier than panning right for oriented content).', 'Lets users change composition and framing post-hoc without re-shooting.', 'Existing image placed in larger canvas with padding masked; diffusion generates to fill padding while attending to original image.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('controlnet', 'ControlNet', '', '', ARRAY['controlnet','condition','guided generation']::text[], 'Core', 'Adding spatial control to image generation—guide the diffusion process with a sketch, pose, or depth map.', 'Giving the AI artist an architectural blueprint before they paint.', 'Sketch stick-figure poses; ControlNet generates realistic people in those poses. Provide edge map; generates images matching those edges.', '[{"text":"Extension of.","id":"diffusionmodelpm"}]'::jsonb, 'Additional control branch learns to inject spatial conditioning (canny edges, pose keypoints, depth) into diffusion UNet. Preserves model quality while adding fine-grained spatial control. Separate ControlNets for different conditions; can stack multiple controls.', 'Drastically improves usability—artists can sketch rough layouts, model fills in details.', 'Conditioning encoder processes control signal (sketch, pose, depth); injected into UNet via cross-attention and additive conditioning at multiple scales.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('upscaling', 'Upscaling', '', '', ARRAY['upscale','super-resolution','image enlargement']::text[], 'Core', 'Enlarging an image while keeping it sharp instead of blurry—add detail where the original is pixelated.', 'Enhancing a blurry security camera footage to see a license plate.', '512x512 image upscaled to 2048x2048 via diffusion; details are plausible and sharp, not just blurred stretching.', '[{"text":"Related to.","id":"superresolution"}]'::jsonb, 'Learned upsampling beats interpolation. Can use diffusion (conditional on low-res image), GANs, or non-learned filters. Training on paired low-res / high-res images. Real-world upscaling includes denoising and artifact removal, not just enlargement.', 'Stretches affordable content creation—generate 512x512 quickly, upscale to 2K for print.', 'Small image encoded as conditioning signal; diffusion or GAN generates high-res version; perceptual loss ensures consistency.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('superresolution', 'Super-Resolution', '', '', ARRAY['super-res','SR','image enhancement']::text[], 'Core', 'Reconstructing high-resolution images from low-resolution inputs—turn 480p into sharp 4K.', 'A detective using CSI enhancement to zoom into a grainy security video.', 'Real-ESRGAN upscales degraded photos (JPEG artifacts, noise) to 4K with plausible detail recovery.', '[{"text":"Variant of.","id":"upscaling"}]'::jsonb, 'Combines upsampling with artifact removal. Training on paired degraded/clean images or blind SR that handles any degradation. Perceptual loss (VGG features) outperforms pixel-level MSE for visual quality. GAN-based methods (ESRGAN) produce sharper results than diffusion but can hallucinate details.', 'Recover missing pixels from old videos, low-res security footage, scans.', 'Learned upsampling (sub-pixel convolution) plus residual blocks; trained with perceptual + adversarial loss.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('speechtotext', 'Speech-to-Text', '', '', ARRAY['STT','ASR','transcription']::text[], 'Core', 'Converting audio of speech into written text—transcribe voice calls, podcasts, lectures.', 'A court reporter typing out everything a witness says.', 'Whisper transcribes English, Spanish, and Japanese from audio files with high accuracy in seconds per minute of audio.', '[{"text":"Inverse of.","id":"texttospeech"},{"text":"Used in meeting transcription."}]'::jsonb, 'Sequence-to-sequence model: encoder processes audio spectrograms, decoder generates text. Training on multilingual data (Whisper: 680k hours) enables zero-shot generalization. Attention layers learn to align audio frames with text. Inference faster than real-time.', 'Unlock content: search podcasts by topic, caption videos, transcribe meetings.', 'Audio preprocessed to Mel spectrogram; encoder extracts features; attention-based decoder generates tokens; beam search finds best hypothesis.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('asr', 'ASR', '', '', ARRAY['automatic speech recognition']::text[], 'Core', 'Automatic speech recognition—converting audio directly to text without human transcription.', 'A secretary who listens and types perfectly, understanding accents and background noise.', 'Google Assistant converts "Play jazz music" from your voice directly to text command.', '[{"text":"Synonym for.","id":"speechtotext"}]'::jsonb, 'Can use hybrid models (acoustic model for audio features + language model for text) or end-to-end (CTC or attention seq2seq). Language model helps correct speech recognition errors via context. Robust to accents, noise, and speaking rate if trained on diverse data.', 'Core capability for voice interfaces and accessibility (closed captions).', 'Acoustic features extracted from audio; HMM or neural net aligns to phones; language model re-ranks hypotheses.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('texttospeech', 'Text-to-Speech', '', '', ARRAY['TTS','speech synthesis','voice synthesis']::text[], 'Core', 'Converting written text into natural-sounding audio—read documents aloud, voiceovers, voice assistants.', 'An actor reading a script into a microphone, but instantly and in any voice.', 'Google TTS converts "Hello, how are you?" to audio in seconds; can choose voice, speed, gender.', '[{"text":"Inverse of text-to-speech."},{"text":"Variant: voice cloning."}]'::jsonb, 'Two-stage: text-to-mel (attention-based model like Tacotron learns to align text to audio features) then mel-to-audio (vocoder like WaveGlow, HiFi-GAN reconstructs waveform). Prosody (pitch, speed, emotion) controllable via attention mask or explicit tokens. Multi-speaker models learn different voices.', 'Accessibility feature; content monetization (audiobooks from text); voice interface.', 'Encoder processes text; decoder attends and generates Mel spectrogram; vocoder converts to waveform.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('voicecloning', 'Voice Cloning', '', '', ARRAY['voice clone','speaker cloning','voice conversion']::text[], 'Core', 'Creating a synthetic voice that sounds like a specific person from a few audio samples—read text in your voice.', 'Recording yourself saying different phonemes then auto-combining them to say anything.', '30 seconds of your voice; AI generates "I will call you later" in your accent, tone, and speaking style.', '[{"text":"Application of text-to-speech."},{"text":"Risk related to deepfakes."}]'::jsonb, 'Speaker encoder learns embeddings from reference audio (speaker verification). TTS conditioned on speaker embedding. Training requires 1-10 hours of target speaker data for good quality; few-shot with 10 seconds possible but lower quality. Can be misused for deepfakes; watermarking and detection critical.', 'Personalization and accessibility; also raises consent and fraud concerns.', 'Speaker encoder extracts speaker embedding from reference; TTS conditioned on embedding; attention learns target speaker prosody.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('texttovideo', 'Text-to-Video', '', '', ARRAY['text2video','video generation','prompt-to-video']::text[], 'Core', 'Creating a video from a text description—"a person dancing in the rain" produces a short video clip.', 'Writing a movie scene description that the AI director turns into footage.', 'Sora takes "a white cat playing with yarn balls" and generates a 60-second video with realistic motion and lighting.', '[{"text":"Extension of image generation."},{"text":"Inverse of video understanding."}]'::jsonb, 'Extends image diffusion to temporal dimension. Model must learn frame-to-frame consistency, realistic motion, and temporal coherence. Latent diffusion (compress frames to latent space) is efficient. Training requires paired video-text data (billions of hours). Inference is slow (1 minute of video takes minutes to generate).', 'Democratizes video creation; enables rapid prototyping and visualization.', 'VAE compresses video frames; temporal UNet diffuses in latent space; CLIP guides; VAE decodes frames back to pixels.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('videogeneration', 'Video Generation', '', '', ARRAY['video synthesis','generative video','video diffusion']::text[], 'Core', 'Generating video sequences with temporal coherence—objects move smoothly, lighting is consistent frame-to-frame.', 'A flipbook that the AI draws, frame by frame, with the same consistent characters and environment.', 'Model generates a 5-second clip of a sunset over a beach; each frame flows naturally to the next.', '[{"text":"Superset of text-to-video."}]'::jsonb, 'Harder than image generation because frames must align temporally. Optical flow loss or temporal consistency loss keeps motion smooth. Some approaches generate sparse keyframes then interpolate; others generate all frames jointly. Computational cost is high (minutes per second).', 'Unlocks video content creation and personalization at scale.', 'Temporal attention or 3D convolutions model motion; optical flow loss enforces temporal consistency; noise schedule spans multiple frames.', 'Multimodal', 80, ARRAY['seed','multimodal']::text[]),
  ('anytoany', 'Any-to-Any', '', '', ARRAY['any2any','unified model']::text[], 'Rising', 'A single model that can convert between any modalities—text to image to video to audio, seamlessly.', 'A universal translator that works for any language pair, not just English-to-Spanish.', 'A future unified model takes text, generates an image, extends to video, adds voiceover—all from one prompt.', '[{"text":"Evolution of multimodal fusion."}]'::jsonb, 'Requires shared latent space where all modalities embed to compatible dimensions. Contrastive learning (like CLIP but for all modalities) aligns them. Few models exist today; mostly hype. Challenges: modality imbalance (text training data >> video), differing dimensions, unequal quality across modalities.', 'If achieved, would dramatically reduce model count and complexity in production.', 'Unified tokenizer/embedder for all modalities; encoder-decoder backbone works across all tasks; cross-modal attention layers.', 'Multimodal', 60, ARRAY['seed','multimodal']::text[]),
  ('crossmodal', 'Cross-Modal', '', '', ARRAY['cross-modality','multimodal interaction']::text[], 'Core', 'Connections between different modalities—image-text alignment, audio-visual sync, text-video coherence.', 'Knowing that a dog bark sound and a dog photo are related even though one is audio and one is visual.', 'CLIP aligns image and text embeddings so "dog" text is close to dog photos; video model aligns audio speech with facial movements.', '[{"text":"Core concept in VLMs."}]'::jsonb, 'Learning alignment requires paired multimodal data. Contrastive learning pulls matching pairs together, pushes mismatches apart. Transformers with cross-attention learn fine-grained alignment (specific words to image regions). Not trivial because modalities have different information content and temporal dynamics.', 'Enables richer search and understanding—find videos by audio description, caption images accurately.', 'Cross-attention between modality encoders; contrastive loss during training; can use fusion early (concatenate) or late (combine embeddings).', 'Multimodal', 80, ARRAY['seed','multimodal']::text[])
